using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class InventoryTraining : TrainingContentBase
{
    public InventoryTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Overview",
            Slug = "inventory-overview",
            Summary = "What the Inventory module does: stock tracking, bin locations, movements, receiving from POs, reservations, cycle counts, and replenishment.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","stock","warehouse","bins"]""",
            ContentJson = """{"body":"## Inventory Overview\n\nThe Inventory module tracks every piece of material and finished goods in your facility — where it is, how much you have, and how it got there. It is the central hub for stock visibility, receiving, transfers, adjustments, and replenishment planning.\n\n### Core Concepts\n\n**Storage Locations** form a hierarchy: Area → Rack → Shelf → Bin. An Area might be 'Warehouse A', a Rack is a physical rack within that area, a Shelf is a level on the rack, and a Bin is a specific slot. Every piece of stock lives in a Bin — the lowest level of the hierarchy. Each location can have a barcode for quick scanning.\n\n**Bin Content** is what is physically stored in a bin. For each thing in the bin — a part, a production run, an assembly, or a piece of tooling — the system tracks the quantity, lot number, status (Stored, Reserved, Ready to Ship, or QC Hold), and who put it there. A single bin can hold several different items.\n\n**Bin Movements** record every stock movement with full traceability. Each movement captures the item, quantity, source location, destination location, the person who moved it, and the reason (Receive, Pick, Restock, QC Release, Ship, Move, Adjustment, Return, Transfer, or Cycle Count).\n\n### How Inventory Connects to Other Features\n\n**Purchase Orders:** When materials arrive from a vendor, the Receiving tab lets you receive against open PO lines. Select the PO line, enter the quantity received, assign a storage location and optional lot number. This creates a bin content record and a movement record with reason 'Receive'.\n\n**Parts Catalog:** The Stock tab shows inventory summarized by part — total on hand, reserved quantity, and available quantity. Expanding a row reveals the bin-level breakdown showing exactly where each part is stored.\n\n**Jobs and Production:** Stock can be reserved for specific jobs. Reservations reduce the available quantity without moving the physical stock. When production picks the material, the reservation is released and a movement with reason 'Pick' is recorded.\n\n**Quality Control:** Received goods can be placed on QC Hold status, preventing them from being picked or shipped until quality inspection is complete. QC Release changes the status back to Stored and records a movement.\n\n**Shipping:** When orders ship, inventory is decremented with a 'Ship' movement reason. Stock marked as 'Ready to Ship' is staged for outbound shipments.\n\n### Tabs at a Glance\n\n- **Stock** — Part-level inventory summary with expandable bin details. Search by part number. Low stock alerts highlight parts below minimum thresholds.\n- **Locations** — Hierarchical tree view of all storage locations. Create, expand, and browse the Area → Rack → Shelf → Bin structure. Select a bin to see its contents.\n- **Movements** — Chronological log of every stock movement. Shows item, quantity, from/to locations, reason, who moved it, and when.\n- **Receiving** — History of goods received against purchase orders. Receive new stock by selecting an open PO line.\n- **Stock Ops** — Transfer stock between bins or adjust quantities with a reason. Two dialogs: Transfer (move stock from one bin to another) and Adjust (correct a quantity with a mandatory reason).\n- **Cycle Counts** — Create and review cycle counts for specific locations. Each count captures expected vs. actual quantities and calculates variance. Counts can be Pending, Approved, or Rejected.\n- **Reservations** — View and manage stock reservations tied to jobs or sales orders. Create new reservations or release existing ones.\n- **Replenishment** — Burn rate analysis and reorder suggestions. Shows 30/60/90-day consumption rates, days of stock remaining, projected stockout dates, and auto-generated reorder suggestions that can be approved into purchase orders.\n- **UOM** — Unit of measure management and conversions.\n\n### Barcode Scanning\n\nThe Inventory page listens for your scanner. When you scan a barcode on this page, it drops the value into the search field and switches to the Stock tab. Storage locations can also have their own barcodes for quick identification during receiving and picking.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory — Guided Tour",
            Slug = "inventory-walkthrough",
            Summary = "A guided tour of the inventory tabs: stock table, receiving, locations tree, movements log, stock operations, cycle counts, reservations, and replenishment.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","walkthrough"]""",
            ContentJson = """{"appRoute":"/inventory/stock","startButtonLabel":"Tour Inventory","steps":[{"element":".tab-bar","popover":{"title":"Inventory Tabs","description":"Inventory is split into tabs: Stock, Locations, Movements, Receiving, Stock Ops, Cycle Counts, Reservations, Replenishment, and Units of Measure. Click any tab to switch views. Each tab has its own web address, so you can bookmark or share a link to any one.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Stock Table","description":"See your inventory grouped by part — the part number, description, material, and how much is on hand, reserved, and available. A row turns red when nothing is available and yellow when stock is running critically low. Click a column heading to sort.","side":"top"}},{"element":"app-input","popover":{"title":"Search Parts","description":"Type a part number, description, or material to filter the list as you go — no search button needed. Click the Clear (✕) button to start over. Scanning a barcode fills this box for you.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(2)","popover":{"title":"Locations Tab","description":"Open the Locations tab to view and manage where you store things. Locations nest from Area to Rack to Shelf to Bin. You can add a new location at any level.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(3)","popover":{"title":"Movements Tab","description":"Review a running log of every stock movement. Each entry shows what moved, how much, from where, to where, who did it, why, and when. This is your complete history.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(4)","popover":{"title":"Receiving Tab","description":"See everything you've received against purchase orders. Click Receive Goods to log an incoming shipment — pick the purchase-order line, enter the quantity, choose where to store it, and add a lot number if you have one.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(5)","popover":{"title":"Stock Operations Tab","description":"Do two things here: Transfer stock from one bin to another, or Adjust a quantity to fix a mistake. Both ask for a reason and both are logged in your movement history.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(6)","popover":{"title":"Cycle Counts Tab","description":"Count a location to check that the shelf matches the system. Each count shows what was expected, what you counted, and the difference. Approve a count and the system corrects itself automatically.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(7)","popover":{"title":"Reservations Tab","description":"See stock that's set aside for specific jobs or orders. Reserved stock stays put but no longer counts as available. Release a reservation once the stock is picked or no longer needed.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(8)","popover":{"title":"Replenishment Tab","description":"See how fast each part is being used, how many days of stock are left, when you'll likely run out, and suggestions for what to reorder. Approve a suggestion to turn it into a purchase order, or dismiss it with a reason.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Field Reference",
            Slug = "inventory-field-reference",
            Summary = "Complete reference for every field, column, status, movement reason, location type, button, and validation rule across all Inventory tabs.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","reference"]""",
            ContentJson = """{"title":"Inventory Field Reference","groups":[{"heading":"Stock Tab — Table Columns","items":[{"label":"Part #","value":"The part number. Click to sort."},{"label":"Description","value":"The part's description. Click to sort."},{"label":"Material","value":"What the part is made of, such as Aluminum 6061 or Steel 1018. Click to sort."},{"label":"On Hand","value":"How much of this part you have across all bins. Click to sort."},{"label":"Reserved","value":"How much is set aside for jobs or orders. Click to sort."},{"label":"Available","value":"On Hand minus Reserved — what you can actually pick or ship. Click to sort."}]},{"heading":"Stock Tab — Expanded Bin Detail","items":[{"label":"Location Path","value":"The full path to the bin, such as Warehouse A > Rack 1 > Shelf 3 > Bin 5."},{"label":"Quantity","value":"How much of the part is in this bin."},{"label":"Reserved Quantity","value":"How much in this bin is set aside for jobs or orders."},{"label":"Available Quantity","value":"Bin quantity minus reserved — what you can actually pick."},{"label":"Status","value":"The bin's status: Stored (ready to use), Reserved (held for a job), Ready to Ship (staged to go out), or QC Hold (waiting for inspection)."},{"label":"Lot Number","value":"An optional lot or batch number for tracking. Shown when set."},{"label":"Lot Expiration Date","value":"When a lot-tracked item expires. Shown when it applies."},{"label":"Supplier Lot Number","value":"The vendor's own lot number, kept separate from yours."}]},{"heading":"Stock Tab — Row Highlighting","items":[{"label":"Red row","value":"Nothing is available — no stock to pick."},{"label":"Yellow row","value":"Stock is running critically low."},{"label":"Normal row","value":"Stock levels are fine."}]},{"heading":"Low Stock Alerts","items":[{"label":"Part Number","value":"The part that's running low."},{"label":"Description","value":"The part's description, so you can spot it."},{"label":"Current Stock","value":"How much you have on hand right now."},{"label":"Min Stock Threshold","value":"The lowest level you want to keep. The alert appears when you drop below it."},{"label":"Reorder Point","value":"The level at which you should reorder. Reaching it means it's time to buy more."}]},{"heading":"Location Types","items":[{"label":"Area","value":"A top-level zone, such as Warehouse A, the Receiving Dock, or the Shipping Area."},{"label":"Rack","value":"A physical rack or shelving unit inside an area."},{"label":"Shelf","value":"A level on a rack."},{"label":"Bin","value":"The lowest level — a specific slot or container. This is where stock actually sits."}]},{"heading":"Location Form Fields (Create Location)","items":[{"label":"Name (required)","value":"Names the location, such as Rack A1, Shelf 3, or Bin 5. Can't be left blank."},{"label":"Type (required)","value":"Pick the level: Area, Rack, Shelf, or Bin."},{"label":"Parent","value":"You don't set this directly — it depends on where you start. Add Location at the top makes a new top-level location; Add child on a selected location nests the new one under it."},{"label":"Barcode","value":"Optional, and shown only for bins. A barcode you can scan to find the bin quickly."},{"label":"Description","value":"Optional. Any notes about the location."}]},{"heading":"Bin Content Statuses","items":[{"label":"Stored","value":"The normal state. Stock is free to pick, transfer, or reserve."},{"label":"Reserved","value":"Held for a specific job or order. Can't be picked for anything else until it's released."},{"label":"Ready to Ship","value":"Staged for an outbound shipment. Waiting to go out."},{"label":"QC Hold","value":"Waiting for a quality check. Can't be picked or shipped until it's released."}]},{"heading":"Movement Reasons","items":[{"label":"Receive","value":"Stock came in from a purchase order. Logged for you when you receive goods."},{"label":"Pick","value":"Stock pulled from a bin for a job or order."},{"label":"Restock","value":"Stock put back in a bin after being picked but not used."},{"label":"QC Release","value":"Stock cleared from a quality hold after passing inspection."},{"label":"Ship","value":"Stock sent to a customer. Logged when a shipment goes out."},{"label":"Move","value":"A general move between bins with no specific business reason."},{"label":"Adjustment","value":"A manual quantity fix. Always needs a reason, such as damaged or miscounted."},{"label":"Return","value":"Stock returned by a customer, or returned to a vendor."},{"label":"Transfer","value":"A formal move between bins, usually across different areas or sites."},{"label":"Cycle Count","value":"A correction from a count difference. Logged for you when a count is approved."}]},{"heading":"Movements Tab — Table Columns","items":[{"label":"Item","value":"The item that moved. Click to sort."},{"label":"Qty","value":"How much moved. Click to sort."},{"label":"From","value":"Where it came from. Blank when stock is coming in, such as a receipt. Click to sort."},{"label":"To","value":"Where it went. Blank when stock is going out, such as a shipment. Click to sort."},{"label":"Reason","value":"Why it moved, in plain words like Received, Picked, or Transferred. Click to sort."},{"label":"By","value":"Who moved it. Click to sort."},{"label":"When","value":"The date and time it moved. Click to sort."}]},{"heading":"Receiving Tab — Table Columns","items":[{"label":"PO #","value":"The purchase order number. Click to sort."},{"label":"Part #","value":"The part you received. Click to sort."},{"label":"Qty","value":"How much you received. Click to sort."},{"label":"Received By","value":"Who received the goods. Click to sort."},{"label":"Location","value":"Where you put the goods. Click to sort."},{"label":"Lot #","value":"The lot or batch number set when receiving. Click to sort."},{"label":"Date","value":"When you received it. Click to sort."}]},{"heading":"Receive Goods Fields","items":[{"label":"PO Line (required)","value":"Pick from the open purchase-order lines that still have quantity left, shown like 'PO-1001 — Part ABC (50 remaining)'. Only lines from purchase orders that are submitted, acknowledged, or partly received show up."},{"label":"Quantity Received (required)","value":"How many items you're receiving. Must be at least 1."},{"label":"Location","value":"Optional. Where the goods will be stored."},{"label":"Lot Number","value":"Optional. A lot or batch number for tracking."},{"label":"Notes","value":"Optional. Anything worth recording, such as condition or discrepancies."}]},{"heading":"Transfer Fields","items":[{"label":"Source (required)","value":"The stock you're moving. Filled in for you when you start from a bin detail row."},{"label":"Destination Location (required)","value":"Where the stock is going."},{"label":"Quantity (required)","value":"How much to move. Must be at least 1."},{"label":"Notes","value":"Optional. The reason or any notes for the move."}]},{"heading":"Adjust Stock Fields","items":[{"label":"Stock (required)","value":"The stock you're correcting. Filled in for you when you start from a bin detail row."},{"label":"New Quantity (required)","value":"The corrected amount, which replaces the current one. Must be 0 or more."},{"label":"Reason (required)","value":"Why you're adjusting, such as damaged goods, recount corrected, or scrap. Can't be left blank."},{"label":"Notes","value":"Optional. Any extra detail about the adjustment."}]},{"heading":"Cycle Counts Tab — Table Columns","items":[{"label":"Location","value":"The location that was counted. Click to sort."},{"label":"Counted By","value":"Who did the count. Click to sort."},{"label":"Date","value":"When the count was done. Click to sort."},{"label":"Status","value":"Pending (waiting for review), Approved (corrections applied), or Rejected (thrown out). Click to sort or filter."},{"label":"Items","value":"How many lines are in the count. Click to sort."},{"label":"Variance","value":"The total difference across all lines. Click to sort."}]},{"heading":"Cycle Count Line Fields","items":[{"label":"Item Name","value":"The part or item being counted."},{"label":"Expected Quantity","value":"What the system had on record before the count."},{"label":"Actual Quantity","value":"What you actually counted."},{"label":"Variance","value":"Actual minus expected. A positive number is a surplus; a negative one is a shortage."},{"label":"Notes","value":"Optional notes explaining the difference."}]},{"heading":"Create Cycle Count Fields","items":[{"label":"Location (required)","value":"The bin or location you want to count."},{"label":"Notes","value":"Optional. Notes for the count, such as quarterly audit or spot check."}]},{"heading":"Reservations Tab — Table Columns","items":[{"label":"Part #","value":"The reserved part's number. Click to sort."},{"label":"Description","value":"The part's description. Click to sort."},{"label":"Bin Location","value":"Where the reserved stock sits. Click to sort."},{"label":"Qty","value":"How much is reserved. Click to sort."},{"label":"Job #","value":"The job the stock is reserved for, if any. Click to sort."},{"label":"Job","value":"The job's title. Click to sort."},{"label":"Notes","value":"Notes on the reservation."},{"label":"Reserved","value":"When the reservation was made. Click to sort."},{"label":"Actions","value":"A Release button to free the reservation."}]},{"heading":"Create Reservation Fields","items":[{"label":"Part (required)","value":"The part to reserve."},{"label":"Stock (required)","value":"The specific stock to reserve from."},{"label":"Job","value":"Optional. The job this reservation is for."},{"label":"Quantity (required)","value":"How much to reserve. Must be more than 0."},{"label":"Notes","value":"Optional. Why you're reserving the stock."}]},{"heading":"Replenishment Tab — Usage Columns","items":[{"label":"Part Number / Description","value":"The part being looked at."},{"label":"Preferred Vendor","value":"The vendor you usually buy this part from."},{"label":"On Hand Stock","value":"How much you have right now."},{"label":"Available Stock","value":"On hand minus reserved."},{"label":"Incoming PO Quantity","value":"How much is on order but not yet received."},{"label":"Earliest PO Arrival","value":"When the soonest open order is expected."},{"label":"Usage Rate (30/60/90 Day)","value":"Average amount used per day over the last 30, 60, or 90 days."},{"label":"Days of Stock Remaining","value":"Available stock divided by how fast you use it."},{"label":"Projected Stockout Date","value":"When you're likely to run out at the current pace."},{"label":"Min Stock Threshold","value":"The lowest level you want to keep."},{"label":"Reorder Point","value":"The level at which you should reorder."},{"label":"Reorder Quantity","value":"How much to order when you do."},{"label":"Lead Time Days","value":"How long the vendor usually takes to deliver."},{"label":"Safety Stock Days","value":"Extra days of stock to keep as a buffer."},{"label":"Needs Reorder","value":"Flags a part at or below its reorder point."}]},{"heading":"Replenishment Tab — Reorder Suggestions","items":[{"label":"Suggestion Status","value":"Pending (waiting on you), Approved (order created), Dismissed (turned down with a reason), or Expired (no longer relevant)."},{"label":"Suggested Quantity","value":"How much to reorder, worked out from usage rate, lead time, and safety stock."},{"label":"Resulting PO","value":"If approved, a link to the purchase order that was created."},{"label":"Dismiss Reason","value":"Needed when you turn a suggestion down. Explains why the reorder wasn't needed."},{"label":"Bulk Approve","value":"Approve several suggestions at once. Orders are grouped by vendor."}]},{"heading":"Buttons and Actions","items":[{"label":"Receive Goods (Receiving tab)","value":"Opens the receive window."},{"label":"Create Location (Locations tab)","value":"Opens the new-location window."},{"label":"Transfer (Stock Ops tab)","value":"Opens the transfer window."},{"label":"Adjust (Stock Ops tab)","value":"Opens the adjust window."},{"label":"Create Cycle Count","value":"Opens the new-count window."},{"label":"Create Reservation","value":"Opens the new-reservation window."},{"label":"Release (Reservations tab)","value":"Frees a reservation so the quantity is available again."},{"label":"Create PO (Low Stock alert)","value":"Takes you to Purchase Orders to order more of the low part."},{"label":"Search / Clear","value":"Search filters the stock list as you type by part number, description, or material — no button needed. Clear (✕) resets it."}]},{"heading":"Barcode Scanning","items":[{"label":"When you scan","value":"Scanning a barcode on the Inventory page drops the value into the search box and switches to the Stock tab."},{"label":"Location barcodes","value":"Each location can have its own barcode so you can find it fast when receiving or moving stock."}]},{"heading":"Rules to Know","items":[{"label":"Location Name","value":"Required. Can't be blank."},{"label":"Location Type","value":"Required. Must be Area, Rack, Shelf, or Bin."},{"label":"PO Line (Receiving)","value":"Required. Pick an open order line that still has quantity left."},{"label":"Quantity Received","value":"Required. Must be at least 1."},{"label":"Transfer Source","value":"Required. Pick the stock to move."},{"label":"Transfer Destination","value":"Required. Pick where it's going."},{"label":"Transfer Quantity","value":"Required. Must be at least 1."},{"label":"Adjust Reason","value":"Required. Can't be blank — every adjustment needs an explanation for the record."},{"label":"Adjust New Quantity","value":"Required. Must be 0 or more."},{"label":"Cycle Count Location","value":"Required. Pick a location to count."},{"label":"Reservation Part / Stock","value":"Required. Pick the part and the specific stock."},{"label":"Reservation Quantity","value":"Required. Must be more than 0."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Knowledge Check",
            Slug = "inventory-quiz",
            Summary = "Test your knowledge of the Inventory module: stock tracking, locations, movements, receiving, cycle counts, reservations, and replenishment.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"inv1","text":"A shipment of raw materials just arrived from your vendor with a purchase order. How do you record it in Forge?","options":[{"id":"a","text":"Go to Inventory → Receiving tab, click Receive Goods, select the PO line, enter quantity, assign a location, and optionally record a lot number","isCorrect":true},{"id":"b","text":"Go to Parts Catalog and manually increase the on-hand quantity for each part"},{"id":"c","text":"Create a new bin movement with reason 'Receive' in the Movements tab"},{"id":"d","text":"Go to Purchase Orders and mark the PO as 'Received'"}],"explanation":"Receiving is done from the Inventory → Receiving tab. Click Receive Goods, select the open PO line (only lines with remaining quantity appear), enter the quantity received, optionally assign a storage location and lot number. This automatically creates a bin content record, updates the PO line, and logs a movement with reason 'Receive'."},{"id":"inv2","text":"What is the correct hierarchy for storage locations in the Inventory module?","options":[{"id":"a","text":"Warehouse → Zone → Aisle → Position"},{"id":"b","text":"Building → Floor → Room → Cabinet"},{"id":"c","text":"Area → Rack → Shelf → Bin","isCorrect":true},{"id":"d","text":"Section → Row → Column → Slot"}],"explanation":"Storage locations follow the hierarchy Area → Rack → Shelf → Bin. Area is the top level (e.g., 'Warehouse A'), Rack is a shelving unit within an area, Shelf is a level on the rack, and Bin is the lowest level where stock is actually stored."},{"id":"inv3","text":"You notice the on-hand quantity for a part doesn't match what's physically on the shelf. What's the correct way to fix this?","options":[{"id":"a","text":"Edit the bin content record directly in the database"},{"id":"b","text":"Go to Stock Ops tab, click Adjust, select the bin content, enter the correct quantity, and provide a mandatory reason","isCorrect":true},{"id":"c","text":"Delete the bin content and re-create it with the correct quantity"},{"id":"d","text":"Create a Transfer moving stock to the same bin with the corrected amount"}],"explanation":"Stock adjustments are done via the Adjust dialog on the Stock Ops tab. You must provide the new quantity and a mandatory reason (e.g., 'recount corrected', 'damaged goods'). This creates a movement record with reason 'Adjustment' for full audit traceability. The reason field cannot be left blank."},{"id":"inv4","text":"A row in the Stock table is highlighted in red. What does this indicate?","options":[{"id":"a","text":"The part has been discontinued and should not be reordered"},{"id":"b","text":"The available quantity is zero or negative — there is no pickable stock","isCorrect":true},{"id":"c","text":"The part is on QC Hold and cannot be used"},{"id":"d","text":"The part's lot has expired and must be disposed of"}],"explanation":"A red row in the Stock table means the available quantity (on hand minus reserved) is zero or negative. This means there is no stock available to pick or ship. A yellow row indicates low stock (available is less than 20% of on-hand)."},{"id":"inv5","text":"What is the difference between the 'Reserved' bin content status and a 'Reservation' record?","options":[{"id":"a","text":"They are the same thing — both refer to stock held for a job"},{"id":"b","text":"'Reserved' is the bin content status flag, while a Reservation is a separate record linking stock to a specific job or sales order with quantity and notes","isCorrect":true},{"id":"c","text":"'Reserved' applies to entire bins, while Reservations apply to individual items"},{"id":"d","text":"'Reserved' is for customer-owned stock, while Reservations are for internal use"}],"explanation":"'Reserved' is a status on a bin content record indicating the stock is held. A Reservation is a separate record that links a specific quantity from a bin content to a job or sales order, with optional notes. Reservations reduce the 'available' quantity shown in the Stock tab. Releasing a reservation makes the quantity available again."},{"id":"inv6","text":"You need to move 50 units of a part from Warehouse A, Rack 1, Bin 3 to Warehouse B, Rack 2, Bin 1. Which feature do you use?","options":[{"id":"a","text":"Create a new Receive record with the destination bin"},{"id":"b","text":"Go to Stock Ops tab, click Transfer, select the source bin content, choose the destination bin, and enter quantity 50","isCorrect":true},{"id":"c","text":"Delete the stock from the first bin and place new stock in the second bin"},{"id":"d","text":"Use the Movements tab to manually create a movement record"}],"explanation":"Stock transfers are done via the Transfer dialog on the Stock Ops tab. Select the source bin content record, choose the destination location, and enter the quantity. This creates a movement record with reason 'Transfer' and updates both bin contents automatically."},{"id":"inv7","text":"What movement reasons are automatically generated by the system (not manually created)?","options":[{"id":"a","text":"Receive (from PO receiving) and Cycle Count (from approved cycle counts)","isCorrect":true},{"id":"b","text":"All reasons are manually selected by the user"},{"id":"c","text":"Only Ship and Pick are automatic"},{"id":"d","text":"Move and Transfer are the only automatic reasons"}],"explanation":"'Receive' movements are automatically created when goods are received against a PO line via the Receiving tab. 'Cycle Count' movements are auto-generated when a cycle count with variance is approved, creating adjustment records. Other reasons like Transfer, Adjustment, Pick, and Ship are created through their respective operations."},{"id":"inv8","text":"A cycle count shows a variance of -5 for a part in Bin 12. What does this mean?","options":[{"id":"a","text":"Five extra units were found that the system didn't know about"},{"id":"b","text":"The system expected 5 more units than were physically counted — there is a shortage of 5","isCorrect":true},{"id":"c","text":"Five units were moved to a different bin during the count"},{"id":"d","text":"The count was rejected because the variance exceeds the threshold"}],"explanation":"A negative variance means the actual count was lower than the expected (system) quantity. A variance of -5 means 5 fewer units were found than the system recorded. When the cycle count is approved, an adjustment movement is created to correct the system quantity to match the physical count."},{"id":"inv9","text":"Which PO statuses allow receiving goods in the Inventory module?","options":[{"id":"a","text":"Only 'Submitted' purchase orders can be received against"},{"id":"b","text":"Submitted, Acknowledged, and Partially Received","isCorrect":true},{"id":"c","text":"Any PO status except Cancelled and Closed"},{"id":"d","text":"Only 'Acknowledged' — the vendor must confirm before receiving is allowed"}],"explanation":"The Receive Goods dialog only shows PO lines from purchase orders with status Submitted, Acknowledged, or Partially Received. Additionally, only lines with remaining quantity (ordered minus already received) greater than zero are shown."},{"id":"inv10","text":"What does the 'Days of Stock Remaining' metric on the Replenishment tab represent?","options":[{"id":"a","text":"The number of days until the next scheduled delivery arrives"},{"id":"b","text":"Available stock divided by the average daily consumption (burn rate) — how long current stock will last at the current usage rate","isCorrect":true},{"id":"c","text":"The number of business days since the last stock receipt"},{"id":"d","text":"The lead time in days for the preferred vendor to deliver"}],"explanation":"Days of Stock Remaining is calculated by dividing available stock by the burn rate (average daily consumption). For example, if you have 100 units available and consume 10 per day, you have 10 days of stock remaining. This drives the Projected Stockout Date and reorder suggestions."},{"id":"inv11","text":"You scan a barcode while on the Inventory page. What happens?","options":[{"id":"a","text":"A dialog opens asking what action to take with the scanned code"},{"id":"b","text":"The scanned value is placed in the search field and the view switches to the Stock tab","isCorrect":true},{"id":"c","text":"The system looks up the barcode in the location database and navigates to that bin"},{"id":"d","text":"Nothing — barcode scanning only works on the Shop Floor display"}],"explanation":"The Inventory page listens for your scanner. When you scan a barcode, the value drops into the search field and the view switches to the Stock tab, so you can look up a part just by scanning its label — no typing."},{"id":"inv12","text":"What is the 'QC Hold' bin content status used for?","options":[{"id":"a","text":"Stock that has failed quality inspection and must be scrapped"},{"id":"b","text":"Stock awaiting quality inspection — it cannot be picked or shipped until QC releases it","isCorrect":true},{"id":"c","text":"Stock that is reserved for quality control testing samples"},{"id":"d","text":"Stock returned by a customer pending quality review"}],"explanation":"QC Hold prevents stock from being picked or shipped until it passes quality inspection. Once inspection is complete, a 'QC Release' movement changes the status back to Stored, making the stock available. This is commonly used for incoming materials that require inspection before use in production."},{"id":"inv13","text":"How are reorder suggestions created in the Replenishment tab?","options":[{"id":"a","text":"Users manually create suggestions by clicking 'Add Suggestion'"},{"id":"b","text":"The system automatically generates suggestions based on burn rate analysis, reorder points, lead times, and safety stock levels","isCorrect":true},{"id":"c","text":"Suggestions are imported from the vendor's catalog system"},{"id":"d","text":"They are copied from the previous month's purchase orders"}],"explanation":"Reorder suggestions are system-generated based on burn rate analysis (30/60/90-day consumption), configured reorder points, lead times, and safety stock days. When available stock drops to or below the reorder point, a suggestion is created with a calculated order quantity. Suggestions can be approved (creating a PO) or dismissed (with a required reason)."},{"id":"inv14","text":"You want to create a new storage location called 'Bin 7' inside 'Rack B2' in 'Warehouse A'. What do you set in the Create Location dialog?","options":[{"id":"a","text":"Name: 'Bin 7', Type: Bin, Parent: select 'Rack B2' from the dropdown","isCorrect":true},{"id":"b","text":"Name: 'Warehouse A > Rack B2 > Bin 7', Type: Area, no parent"},{"id":"c","text":"Name: 'Bin 7', Type: Shelf, Parent: 'Warehouse A'"},{"id":"d","text":"You must first create 'Bin 7' as an Area, then move it under Rack B2"}],"explanation":"To create a bin inside an existing rack, set the Name to 'Bin 7', select Type as 'Bin' (the lowest level), and set the Parent to 'Rack B2' from the dropdown. The system will nest it in the hierarchy: Warehouse A → Rack B2 → Bin 7. The full path is displayed in stock tables and movement logs."},{"id":"inv15","text":"What happens when you approve a cycle count that has variances?","options":[{"id":"a","text":"The variances are logged but no quantities are changed — you must manually adjust each one"},{"id":"b","text":"Adjustment movements are automatically generated to correct system quantities to match the physical counts","isCorrect":true},{"id":"c","text":"An email is sent to the warehouse manager listing all discrepancies"},{"id":"d","text":"The count is flagged for a second verification before any changes are made"}],"explanation":"Approving a cycle count with variances automatically generates adjustment movements with reason 'Cycle Count' to correct the system quantities. Each line with a non-zero variance gets an adjustment to make the system quantity match the actual counted quantity. This maintains the audit trail while keeping inventory accurate."}]}"""
        });

        // ── Inventory Home (Article) ─────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Home — The Friendly Landing",
            Slug = "inventory-home",
            Summary = "The default Inventory landing built for the shop floor: three tabs (Kiosk, Tasks, Dashboard) over friendly stock verbs — Receive, Use, Count, Find — with a one-click jump to the detailed power view.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/inventory/home/kiosk","/inventory/home/tasks","/inventory/home/dashboard"]""",
            Tags = """["inventory","home","kiosk","stock","verbs"]""",
            ContentJson = """{"body":"## Inventory Home\n\nWhen you open Inventory, you land on **Inventory Home** — not the detailed tab grid. Home is a deliberately simple, low-friction surface designed for the people who actually touch stock: receiving clerks, machinists, and anyone who needs to record a stock change in a few taps without learning the full warehouse model.\n\nHome has three tabs across the top — Kiosk, Tasks, and Dashboard. Each tab has its own web address, so you can bookmark the one you use most or share a direct link to it.\n\n### Two views of inventory, one feature\n\nForge gives you **two** ways into the same stock:\n\n- **Inventory Home** (where you land) — friendly verbs, big buttons, three at-a-glance tabs. Built for daily floor use.\n- **The detailed power view** (Stock / Locations / Movements / Receiving / Stock Ops / Cycle Counts / Reservations / Replenishment / Units of Measure) — the full warehouse model with bins, lots, and audit trails. Reach it from the **Manage Inventory** link in the top-right of Home.\n\nNothing you do on Home is \"different data\" — receiving a part on Home and receiving it on the detailed Receiving tab both write the same bin contents and the same movement records. Home is just a faster door into the same warehouse.\n\n### The friendly stock verbs\n\nHome is organized around four plain-language verbs instead of warehouse jargon:\n\n- **Receive** — stock came IN. Add quantity to a part (e.g., a delivery arrived, or you finished making something). Receive also lets you record a lot number.\n- **Use** — stock went OUT. Subtract quantity from a part (e.g., it was consumed by a job or scrapped).\n- **Count** — set the TRUE on-hand quantity. Use this when you physically counted the shelf and want the system to match reality. Count overwrites the on-hand number rather than adding or subtracting.\n- **Find** — look up a part. On the Kiosk tab this jumps you to the Tasks tab so you can search; it is a navigation shortcut, not a stock change.\n\nReceive, Use, and Count each open a small dialog: pick the part (pre-filled if you started from a row), enter a quantity, optionally pick a location and add a reason/notes. Receive additionally shows a Lot number field. Tap the action button and the change is recorded immediately with a confirmation snackbar.\n\n### The three tabs\n\n**Kiosk (default).** Four big touch-friendly buttons — Receive, Use, Count, Find — arranged two-per-row. This is the tap-and-go view for a wall-mounted tablet or a quick action at a workstation. One action at a time, nothing else competing for attention.\n\n**Tasks.** A working list: a search box, a row of the same verb buttons, a low-stock strip, and a table of parts with on-hand quantities. Each table row has inline Receive and Use buttons so you can act on a specific part without retyping its number. If a part is below its minimum, it shows up as a warning chip in the low-stock strip — tap the chip to Receive against it.\n\n**Dashboard.** At-a-glance numbers: total parts tracked, total units on hand, and a low-stock count (which turns amber when anything is low). Below the numbers is the full low-stock list — part number, description, current-vs-minimum quantity, and a Receive shortcut on each line. When nothing is low, you get a clean \"all stocked\" confirmation.\n\n### Locations are optional here\n\nIf your site tracks stock in one place, the **Location** field is hidden in the action panels and everything goes to the default location — you don't have to think about bins. If your site tracks multiple locations, a Location menu appears so you can say exactly which bin the stock went into or came out of. Either way, the action itself is the same; only the optional location detail changes.\n\n### When to use Home vs. the detailed view\n\nUse **Home** for the everyday actions: a delivery arrived, a job consumed material, you recounted a shelf, you need to glance at what's low. Use the **detailed view** when you need the warehouse mechanics: moving stock between specific bins, transferring between areas, running and approving cycle counts, managing reservations against jobs, receiving formally against a purchase-order line, or reviewing the full movement audit trail and replenishment analysis.","sections":[]}"""
        });

        // ── Inventory Home — Guided Tour (Walkthrough) ───────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Home — Guided Tour",
            Slug = "inventory-home-walkthrough",
            Summary = "A short tour of the friendly Inventory Home landing: the Kiosk big-button view, the three tabs, the stock verbs, and the jump to the detailed Manage Inventory view.",
            ContentType = TrainingContentType.Walkthrough,
