            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/inventory/home/kiosk"]""",
            Tags = """["inventory","home","kiosk","walkthrough"]""",
            ContentJson = """{"appRoute":"/inventory/home/kiosk","startButtonLabel":"Tour Inventory Home","steps":[{"element":".inv-home__hero","popover":{"title":"Inventory Home","description":"This is where Inventory opens — a friendly, simple landing built for the shop floor. The title and subtitle tell you where you are, and everything below works on the same stock as the detailed warehouse view.","side":"bottom"}},{"element":".inv-home__manage","popover":{"title":"Manage Inventory","description":"Need the full warehouse tools — bins, locations, movements, cycle counts, reservations, replenishment? This link in the top-right opens the detailed view. It shares the same stock as Home; it's just the door to the advanced tools.","side":"left"}},{"element":".tab-bar","popover":{"title":"Three Tabs","description":"Home has three views: Kiosk (big buttons, one action at a time — the default), Tasks (a search box and a working list of parts you can act on), and Dashboard (totals and what's low). Each tab has its own link you can bookmark.","side":"bottom"}},{"element":".tab:nth-child(1)","popover":{"title":"Kiosk Tab","description":"The Kiosk tab — where you are now — is the tap-and-go view, great for a wall-mounted tablet. It shows four large buttons for the everyday stock actions and nothing else, so nothing gets in your way.","side":"bottom"}},{"element":".inv-home__hint","popover":{"title":"One Action at a Time","description":"Kiosk is built for single, focused actions. Tap a button, fill in the small panel, and you're done — the change is saved right away with a confirmation.","side":"bottom"}},{"element":"app-quick-action-panel","popover":{"title":"The Stock Actions","description":"Four plain actions: Receive (stock came in — also lets you record a lot number), Use (stock went out), Count (set the true amount after a physical count), and Find (look up a part — this jumps to the Tasks tab). Receive, Use, and Count each open a quick panel: pick the part, enter a quantity, add a location and reason if you like, then confirm.","side":"top"}},{"element":".tab:nth-child(2)","popover":{"title":"Tasks Tab","description":"Switch here for a working list: a search box, the same action buttons, a strip that warns about low stock, and a table of parts with their on-hand amounts. Each row has its own Receive and Use buttons so you can act on a part without retyping its number.","side":"bottom"}},{"element":".tab:nth-child(3)","popover":{"title":"Dashboard Tab","description":"The Dashboard shows quick numbers — total parts, total units on hand, and a low-stock count that turns amber when anything is low — followed by the full low-stock list with a Receive shortcut on each line. Use it for a quick health check.","side":"bottom"}}]}"""
